def main():
    conn = sqlite3.connect(DB_PATH)
    try:
        cur = conn.cursor()
        cur.execute("DELETE FROM menu_items")
        for item in ITEMS:
            item_id, cat, name, price, weight, badge, tags, img, desc, ingr = item
            cur.execute(
                """
                INSERT INTO menu_items
                    (id, cat, name, price, discount_percent, weight, badge, tags_json, img, desc, ingr, is_active, created_at, updated_at)
                VALUES
                    (?, ?, ?, ?, 0, ?, ?, ?, ?, ?, ?, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP)
                """,
                (item_id, cat, name, price, weight, badge, json.dumps(tags, ensure_ascii=False), img, desc, ingr),
            )
        conn.commit()
        print(f"Seeded {len(ITEMS)} menu items into {DB_PATH}")
    finally:
        conn.close()


if __name__ == "__main__":
    main()
